{
  "name": "flow",
  "description": "A non-judgmental mood tracking application designed for Bipolar Disorder management. Focuses on observing patterns without pressure to 'be cured'.",
  "requestFramePermissions": [
    "camera"
  ]
}

export enum MoodLevel {
  ROCKET = 'rocket', // Mania
  FERRIS_WHEEL = 'ferris_wheel', // Hypomania
  STEADY = 'steady', // Euthymia (Baseline)
  HOLDING_BREATH = 'holding_breath', // Mild Depression
  DEEP_SEA = 'deep_sea', // Moderate/Severe Depression
  ABYSS = 'abyss' // Crisis
}

export interface MoodConfig {
  id: MoodLevel;
  label: string;
  description: string;
  color: string;
  iconName: string; // Mapping to Lucide icon manually
  value: number; // For charting (-3 to +3)
}

export interface SleepData {
  hours: number;
  difficultyFallingAsleep: boolean;
  earlyWakeUp: boolean;
  fallAsleepTime?: string;
  wakeUpTime?: string;
}

export interface MedicationData {
  taken: boolean;
  name: string;
  sideEffects: string;
}

export interface DailyLog {
  id: string;
  date: string;
  mood: MoodLevel;
  sleep: SleepData;
  menstrualDay: number; // 0 = not menstruating, 1-7+ = day of cycle
  triggers: string[];
  medication: MedicationData;
  note: string;
}

export interface InsightMessage {
  text: string;
  type: 'comfort' | 'pattern' | 'safety';
}

import React from 'react';
import { Moon, Clock, Sunrise } from 'lucide-react';
import { SleepData } from '../types';

interface PhysiologicalSectionProps {
  sleepData: SleepData;
  onSleepChange: (data: SleepData) => void;
  menstrualDay: number;
  onMenstrualChange: (day: number) => void;
}

const PhysiologicalSection: React.FC<PhysiologicalSectionProps> = ({
  sleepData,
  onSleepChange,
  menstrualDay,
  onMenstrualChange
}) => {

  const handleSleepUpdate = (updates: Partial<SleepData>) => {
    onSleepChange({ ...sleepData, ...updates });
  };

  return (
    <div className="space-y-4">
      <h2 className="text-sm font-bold text-stone-400 tracking-wide uppercase">生理节律 (Rhythm)</h2>

      <div className="bg-white rounded-3xl p-5 shadow-sm border border-stone-100 space-y-6">

        {/* Sleep Section */}
        <div className="space-y-4">
          <div className="flex justify-between items-center text-stone-600">
            <div className="flex items-center gap-2">
              <Moon size={18} className="text-stone-400" />
              <span className="text-sm font-bold text-stone-700">昨夜睡眠时长</span>
            </div>
            <span className="text-xl font-bold font-mono text-stone-700">{sleepData.hours}<span className="text-xs font-normal text-stone-400 ml-1">h</span></span>
          </div>

          <input 
            type="range" 
            min="0" 
            max="14" 
            step="0.5"
            value={sleepData.hours}
            onChange={(e) => handleSleepUpdate({ hours: parseFloat(e.target.value) })}
            className="w-full h-2 bg-stone-100 rounded-lg appearance-none cursor-pointer accent-stone-600"
          />

          {/* Sleep Anomalies Toggles */}
          <div className="grid grid-cols-2 gap-3 pt-2">
            <button
              onClick={() => handleSleepUpdate({ difficultyFallingAsleep: !sleepData.difficultyFallingAsleep })}
              className={`p-3 rounded-xl text-xs font-medium border flex flex-col items-center gap-2 transition-all ${
                sleepData.difficultyFallingAsleep 
                  ? 'bg-stone-800 text-white border-stone-800' 
                  : 'bg-stone-50 text-stone-400 border-stone-100'
              }`}
            >
              <span>入睡困难</span>
            </button>
            <button
              onClick={() => handleSleepUpdate({ earlyWakeUp: !sleepData.earlyWakeUp })}
              className={`p-3 rounded-xl text-xs font-medium border flex flex-col items-center gap-2 transition-all ${
                sleepData.earlyWakeUp 
                  ? 'bg-stone-800 text-white border-stone-800' 
                  : 'bg-stone-50 text-stone-400 border-stone-100'
              }`}
            >
              <span>早醒</span>
            </button>
          </div>

          {/* Conditional Time Inputs */}
          {(sleepData.difficultyFallingAsleep || sleepData.earlyWakeUp) && (
            <div className="grid grid-cols-2 gap-3 animate-slide-in">
               <div className={`transition-opacity ${sleepData.difficultyFallingAsleep ? 'opacity-100' : 'opacity-30 pointer-events-none'}`}>
                 <label className="flex items-center gap-1 text-[10px] uppercase font-bold text-stone-400 mb-1">
                   <Clock size={10} /> 实际入睡
                 </label>
                 <input 
                   type="time" 
                   value={sleepData.fallAsleepTime || ''}
                   onChange={(e) => handleSleepUpdate({ fallAsleepTime: e.target.value })}
                   className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2 text-xs font-mono text-stone-700 focus:ring-1 focus:ring-stone-400 outline-none"
                 />
               </div>
               <div className={`transition-opacity ${sleepData.earlyWakeUp ? 'opacity-100' : 'opacity-30 pointer-events-none'}`}>
                 <label className="flex items-center gap-1 text-[10px] uppercase font-bold text-stone-400 mb-1">
                   <Sunrise size={10} /> 实际醒来
                 </label>
                 <input 
                   type="time" 
                   value={sleepData.wakeUpTime || ''}
                   onChange={(e) => handleSleepUpdate({ wakeUpTime: e.target.value })}
                   className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2 text-xs font-mono text-stone-700 focus:ring-1 focus:ring-stone-400 outline-none"
                 />
               </div>
            </div>
          )}
        </div>

        <div className="w-full h-px bg-stone-100" />

        {/* Menstrual Cycle (Pink Dots) */}
        <div className="space-y-3">
          <div className="flex justify-between items-center">
             <span className="text-sm font-bold text-stone-700">生理期追踪</span>
             <span className="text-xs text-rose-400 font-medium">
                {menstrualDay === 0 ? "非经期" : `Day ${menstrualDay}`}
             </span>
          </div>

          <div className="flex justify-between items-center bg-stone-50 p-3 rounded-2xl">
            <button 
               onClick={() => onMenstrualChange(0)}
               className={`text-xs px-3 py-1 rounded-md transition-colors ${menstrualDay === 0 ? 'bg-stone-200 text-stone-600' : 'text-stone-400'}`}
            >
              无
            </button>
            <div className="flex gap-2">
              {[1, 2, 3, 4, 5, 6, 7].map((day) => (
                <button
                  key={day}
                  onClick={() => onMenstrualChange(menstrualDay === day ? 0 : day)}
                  className={`
                    w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold transition-all duration-300
                    ${menstrualDay === day 
                      ? 'bg-rose-400 text-white shadow-md scale-110' 
                      : 'bg-white border border-stone-200 text-stone-300 hover:border-rose-200'
                    }
                  `}
                >
                  {day === 7 ? '+' : day}
                </button>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PhysiologicalSection;

import React from 'react';
import { Zap, Coffee, Wine, Users, AlertTriangle, Moon } from 'lucide-react';

interface ContextualTriggersProps {
  selectedTriggers: string[];
  onToggle: (trigger: string) => void;
}

const TRIGGERS = [
  { id: 'conflict', label: '冲突', icon: Zap },
  { id: 'stress', label: '压力', icon: AlertTriangle },
  { id: 'late_night', label: '熬夜', icon: Moon },
  { id: 'caffeine', label: '咖啡因', icon: Coffee },
  { id: 'alcohol', label: '酒精', icon: Wine },
  { id: 'social', label: '社交过载', icon: Users },
];

const ContextualTriggers: React.FC<ContextualTriggersProps> = ({ selectedTriggers, onToggle }) => {
  return (
    <div className="space-y-3">
      <div className="flex justify-between items-baseline">
        <h2 className="text-sm font-bold text-stone-400 tracking-wide uppercase">背景因素</h2>
        <span className="text-[10px] text-stone-300">多选 / 可跳过</span>
      </div>

      <div className="grid grid-cols-3 gap-2">
        {TRIGGERS.map((item) => {
          const isSelected = selectedTriggers.includes(item.id);
          const Icon = item.icon;

          return (
            <button
              key={item.id}
              onClick={() => onToggle(item.id)}
              className={`
                flex flex-col items-center justify-center py-3 px-2 rounded-xl transition-all duration-200 border
                ${isSelected 
                  ? 'bg-stone-700 text-stone-50 border-stone-700 shadow-md' 
                  : 'bg-white text-stone-500 border-stone-100 hover:border-stone-200'
                }
              `}
            >
              <Icon size={18} className={`mb-1 ${isSelected ? 'text-stone-200' : 'text-stone-400'}`} />
              <span className="text-xs font-medium">{item.label}</span>
            </button>
          );
        })}
      </div>
    </div>
  );
};

export default ContextualTriggers;

import React, { useState, useEffect } from 'react';
import { Pill, Camera, Check, Edit2 } from 'lucide-react';
import { MedicationData } from '../types';

interface MedicationSectionProps {
  data: MedicationData;
  onChange: (data: MedicationData) => void;
}

const MedicationSection: React.FC<MedicationSectionProps> = ({ data, onChange }) => {
  const [isEditingName, setIsEditingName] = useState(false);

  // Load saved medication name on mount
  useEffect(() => {
    const savedName = localStorage.getItem('userMedicationName');
    if (savedName && !data.name) {
      onChange({ ...data, name: savedName });
    }
  }, []);

  const handleNameSave = (newName: string) => {
    onChange({ ...data, name: newName });
    localStorage.setItem('userMedicationName', newName);
  };

  const toggleTaken = () => {
    onChange({ ...data, taken: !data.taken });
  };

  const handlePhotoClick = () => {
    console.log('Camera triggered');
    // In a real app, this would open the camera stream
    alert("Camera permission requested for medication recognition.");
  };

  return (
    <div className="space-y-4">
      <h2 className="text-sm font-bold text-stone-400 tracking-wide uppercase">药物记录</h2>

      <div className={`
        bg-white rounded-3xl p-6 shadow-sm border transition-all duration-500 overflow-hidden
        ${data.taken ? 'border-emerald-100 bg-emerald-50/30' : 'border-stone-100'}
      `}>
        {/* Primary Toggle */}
        <div className="flex flex-col items-center justify-center">
          <button
            onClick={toggleTaken}
            className={`
              relative group flex items-center justify-center
              w-20 h-20 rounded-full transition-all duration-500 ease-out shadow-sm
              ${data.taken 
                ? 'bg-emerald-500 text-white ring-4 ring-emerald-100 shadow-emerald-200' 
                : 'bg-stone-100 text-stone-400 hover:bg-stone-200'
              }
            `}
          >
            {data.taken ? (
              <Check size={36} className="scale-100 transition-transform duration-300" />
            ) : (
              <Pill size={36} className="transition-transform duration-300" />
            )}
          </button>
          <span className={`mt-3 text-xs font-bold tracking-wide transition-colors ${data.taken ? 'text-emerald-600' : 'text-stone-400'}`}>
            {data.taken ? "今日已服药" : "点击记录服药"}
          </span>
        </div>

        {/* Expanded Details */}
        <div className={`transition-all duration-500 ease-in-out ${data.taken ? 'max-h-96 opacity-100 mt-6' : 'max-h-0 opacity-0 overflow-hidden'}`}>
          <div className="space-y-4 pt-4 border-t border-emerald-100/50">

            {/* Drug Name Input */}
            <div className="space-y-1">
              <label className="text-[10px] uppercase font-bold text-stone-400">药物名称</label>
              <div className="flex gap-2">
                <div className="relative flex-1">
                   <input
                    type="text"
                    value={data.name}
                    placeholder="输入药物名称..."
                    disabled={!isEditingName && data.name.length > 0}
                    onChange={(e) => handleNameSave(e.target.value)}
                    className="w-full bg-white border border-stone-200 rounded-xl px-3 py-3 text-sm text-stone-700 focus:ring-2 focus:ring-emerald-200 outline-none disabled:bg-stone-50 disabled:text-stone-500"
                  />
                  {data.name.length > 0 && !isEditingName && (
                    <button 
                      onClick={() => setIsEditingName(true)}
                      className="absolute right-3 top-3 text-stone-400 hover:text-stone-600"
                    >
                      <Edit2 size={14} />
                    </button>
                  )}
                  {isEditingName && (
                     <button 
                      onClick={() => setIsEditingName(false)}
                      className="absolute right-3 top-3 text-emerald-500 hover:text-emerald-700 text-xs font-bold"
                    >
                      OK
                    </button>
                  )}
                </div>
                <button 
                  onClick={handlePhotoClick}
                  className="bg-stone-100 hover:bg-stone-200 text-stone-500 p-3 rounded-xl transition-colors"
                  title="拍照识别"
                >
                  <Camera size={20} />
                </button>
              </div>
            </div>

            {/* Side Effects */}
            <div className="space-y-1">
              <label className="text-[10px] uppercase font-bold text-stone-400">副作用 / 备注</label>
              <textarea
                value={data.sideEffects}
                onChange={(e) => onChange({ ...data, sideEffects: e.target.value })}
                placeholder="例如：手抖、嗜睡、口渴..."
                className="w-full bg-white border border-stone-200 rounded-xl px-3 py-3 text-sm text-stone-700 min-h-[80px] focus:ring-2 focus:ring-emerald-200 outline-none resize-none"
              />
            </div>

          </div>
        </div>

      </div>
    </div>
  );
};

export default MedicationSection;

import { GoogleGenAI } from "@google/genai";
import { MoodLevel } from "../types";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getCompanionInsight = async (
  mood: MoodLevel, 
  context: { 
    triggers: string[], 
    sleepHours: number, 
    medicationTaken: boolean,
    sleepIssues: string[]
  }
): Promise<string> => {
  try {
    if (!process.env.API_KEY) {
      return "Gemini API Key missing. Unable to generate insight.";
    }

    const moodPrompts: Record<MoodLevel, string> = {
      [MoodLevel.ROCKET]: "State: Mania/Impulsive. Risk high.",
      [MoodLevel.FERRIS_WHEEL]: "State: Hypomania/Creative. Energy high.",
      [MoodLevel.STEADY]: "State: Baseline/Euthymia.",
      [MoodLevel.HOLDING_BREATH]: "State: Mild Depression/Masking.",
      [MoodLevel.DEEP_SEA]: "State: Moderate Depression/Slow.",
      [MoodLevel.ABYSS]: "State: Crisis/Darkness.",
    };

    const triggersText = context.triggers.length > 0 ? `Background factors: ${context.triggers.join(', ')}.` : "No specific triggers.";
    const sleepText = `Sleep: ${context.sleepHours}h (${context.sleepIssues.join(', ') || 'Normal'}).`;
    const medText = context.medicationTaken ? "Meds taken." : "Meds NOT taken.";

    const prompt = `
      You are a companion for someone with Bipolar Disorder.
      Current Status: ${moodPrompts[mood]}
      Context: ${triggersText} ${sleepText} ${medText}

      Task: Write a SINGLE sentence (max 25 words).
      Goal: Connect the context (sleep/triggers) to the mood if relevant. Be gentle.
      Tone: Non-judgmental, observant.
      Forbidden words: "hope", "cure", "happy", "should".
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text?.trim() || "Recorded.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Recorded.";
  }
};

import React, { useState, useEffect } from 'react';
import { HashRouter } from 'react-router-dom';
import { BookOpen, Settings, BarChart2 } from 'lucide-react';

import MoodSelector from './components/MoodSelector';
import ContextualTriggers from './components/ContextualTriggers';
import MedicationSection from './components/MedicationSection';
import SafetyModal from './components/SafetyModal';
import PatternChart from './components/PatternChart';
import PhysiologicalSection from './components/PhysiologicalSection';

import { MoodLevel, SleepData, MedicationData } from './types';
import { getCompanionInsight } from './services/geminiService';

const App: React.FC = () => {
  // Navigation View State
  const [currentView, setCurrentView] = useState<'diary' | 'insights'>('diary');

  // Core Data State
  const [selectedMood, setSelectedMood] = useState<MoodLevel | null>(null);

  // New: Contextual Triggers
  const [triggers, setTriggers] = useState<string[]>([]);

  // New: Physiological Data
  const [sleepData, setSleepData] = useState<SleepData>({
    hours: 7.0,
    difficultyFallingAsleep: false,
    earlyWakeUp: false
  });
  const [menstrualDay, setMenstrualDay] = useState<number>(0);

  // New: Medication Data
  const [medication, setMedication] = useState<MedicationData>({
    taken: false,
    name: '',
    sideEffects: ''
  });

  // System State
  const [safetyOpen, setSafetyOpen] = useState(false);
  const [companionText, setCompanionText] = useState<string>("");
  const [loadingInsight, setLoadingInsight] = useState(false);

  // Safety trigger
  useEffect(() => {
    if (selectedMood === MoodLevel.ABYSS) {
      setSafetyOpen(true);
    }
  }, [selectedMood]);

  // Insight generator with enriched context
  useEffect(() => {
    let isMounted = true;
    if (selectedMood) {
      setLoadingInsight(true);

      const sleepIssues = [];
      if (sleepData.difficultyFallingAsleep) sleepIssues.push("Hard to sleep");
      if (sleepData.earlyWakeUp) sleepIssues.push("Early wake");

      getCompanionInsight(selectedMood, {
        triggers,
        sleepHours: sleepData.hours,
        medicationTaken: medication.taken,
        sleepIssues
      })
        .then(text => {
          if(isMounted) {
            setCompanionText(text);
            setLoadingInsight(false);
          }
        });
    }
    return () => { isMounted = false; };
  }, [selectedMood, triggers, sleepData.hours, medication.taken]);

  const toggleTrigger = (triggerId: string) => {
    if (triggers.includes(triggerId)) {
      setTriggers(triggers.filter(t => t !== triggerId));
    } else {
      setTriggers([...triggers, triggerId]);
    }
  };

  const handleMoodSelect = (mood: MoodLevel) => {
    setSelectedMood(mood);
  };

  return (
    <HashRouter>
      <div className="min-h-screen bg-stone-50 pb-24 max-w-lg mx-auto shadow-2xl overflow-hidden relative font-sans">

        {/* Header */}
        <header className="px-6 py-6 flex justify-between items-center bg-stone-50/80 backdrop-blur-sm sticky top-0 z-10">
          <div>
            <h1 className="text-2xl font-bold text-stone-800 tracking-tight">Fluctuations</h1>
            <p className="text-xs text-stone-400 mt-0.5">允许波动，精准记录</p>
          </div>
          <button className="text-stone-400 hover:text-stone-600 transition-colors bg-white p-2 rounded-full shadow-sm">
            <Settings size={20} />
          </button>
        </header>

        <main className="px-6 space-y-8 animate-slide-in">

          {currentView === 'diary' ? (
            <>
              {/* Section 1: Mood & Companion Insight */}
              <section className="space-y-3">
                 <div className="flex justify-between items-end">
                    <h2 className="text-sm font-bold text-stone-400 tracking-wide uppercase">当前状态</h2>
                    {selectedMood && (
                       <span className={`text-[10px] px-3 py-1.5 rounded-full bg-stone-200 text-stone-600 animate-fade-in max-w-[200px] truncate`}>
                          {loadingInsight ? "..." : companionText}
                       </span>
                    )}
                 </div>
                <MoodSelector 
                  selectedMood={selectedMood} 
                  onSelect={handleMoodSelect} 
                />
              </section>

              {/* Section 2: Contextual Triggers (New) */}
              <section>
                 <ContextualTriggers 
                    selectedTriggers={triggers}
                    onToggle={toggleTrigger}
                 />
              </section>

              {/* Section 3: Physiological (Sleep & Cycle Updated) */}
              <section>
                <PhysiologicalSection 
                  sleepData={sleepData}
                  onSleepChange={setSleepData}
                  menstrualDay={menstrualDay}
                  onMenstrualChange={setMenstrualDay}
                />
              </section>

              {/* Section 4: Medication (New Location & Logic) */}
              <section>
                <MedicationSection 
                  data={medication}
                  onChange={setMedication}
                />
              </section>
            </>
          ) : (
            /* INSIGHTS VIEW */
            <div className="space-y-6 animate-slide-in">
              <div className="bg-stone-900 text-stone-100 p-6 rounded-3xl shadow-lg">
                <h2 className="text-xl font-bold mb-2">多维模式洞察</h2>
                <p className="text-stone-400 text-sm leading-relaxed">
                  下图展示了情绪波动与生理节律（睡眠、经期）的潜在关联。
                </p>
              </div>
              <PatternChart />
            </div>
          )}

          <div className="h-4"></div>
        </main>

        {/* Floating Navigation */}
        <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-xl border-t border-stone-100 max-w-lg mx-auto z-40 pb-safe">
          <div className="flex justify-around py-4">
            <button 
              onClick={() => setCurrentView('diary')}
              className={`flex flex-col items-center gap-1 transition-colors ${currentView === 'diary' ? 'text-stone-800' : 'text-stone-400 hover:text-stone-600'}`}
            >
              <BookOpen size={22} className={currentView === 'diary' ? 'fill-stone-200' : ''} />
              <span className="text-[10px] font-bold">日记</span>
            </button>
            <button 
              onClick={() => setCurrentView('insights')}
              className={`flex flex-col items-center gap-1 transition-colors ${currentView === 'insights' ? 'text-stone-800' : 'text-stone-400 hover:text-stone-600'}`}
            >
              <BarChart2 size={22} className={currentView === 'insights' ? 'fill-stone-200' : ''} />
              <span className="text-[10px] font-bold">洞察</span>
            </button>
          </div>
        </nav>

        {/* Safety Modal */}
        <SafetyModal 
          isOpen={safetyOpen} 
          onClose={() => setSafetyOpen(false)} 
        />

      </div>
    </HashRouter>
  );
};

export default App;

