import { GoogleGenAI } from "@google/genai";
import { MoodLevel } from "../types";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getCompanionInsight = async (
  mood: MoodLevel, 
  context: { 
    triggers: string[], 
    sleepHours: number, 
    medicationTaken: boolean,
    sleepIssues: string[]
  }
): Promise<string> => {
  try {
    if (!process.env.API_KEY) {
      return "Gemini API Key missing. Unable to generate insight.";
    }

    const moodPrompts: Record<MoodLevel, string> = {
      [MoodLevel.ROCKET]: "State: Mania/Impulsive. Risk high.",
      [MoodLevel.FERRIS_WHEEL]: "State: Hypomania/Creative. Energy high.",
      [MoodLevel.STEADY]: "State: Baseline/Euthymia.",
      [MoodLevel.HOLDING_BREATH]: "State: Mild Depression/Masking.",
      [MoodLevel.DEEP_SEA]: "State: Moderate Depression/Slow.",
      [MoodLevel.ABYSS]: "State: Crisis/Darkness.",
    };

    const triggersText = context.triggers.length > 0 ? `Background factors: ${context.triggers.join(', ')}.` : "No specific triggers.";
    const sleepText = `Sleep: ${context.sleepHours}h (${context.sleepIssues.join(', ') || 'Normal'}).`;
    const medText = context.medicationTaken ? "Meds taken." : "Meds NOT taken.";

    const prompt = `
      You are a companion for someone with Bipolar Disorder.
      Current Status: ${moodPrompts[mood]}
      Context: ${triggersText} ${sleepText} ${medText}

      Task: Write a SINGLE sentence (max 25 words).
      Goal: Connect the context (sleep/triggers) to the mood if relevant. Be gentle.
      Tone: Non-judgmental, observant.
      Forbidden words: "hope", "cure", "happy", "should".
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text?.trim() || "Recorded.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Recorded.";
  }
};

import React, { useState, useEffect } from 'react';
import { HashRouter } from 'react-router-dom';
import { BookOpen, Settings, BarChart2 } from 'lucide-react';

import MoodSelector from './components/MoodSelector';
import ContextualTriggers from './components/ContextualTriggers';
import MedicationSection from './components/MedicationSection';
import SafetyModal from './components/SafetyModal';
import PatternChart from './components/PatternChart';
import PhysiologicalSection from './components/PhysiologicalSection';

import { MoodLevel, SleepData, MedicationData } from './types';
import { getCompanionInsight } from './services/geminiService';

const App: React.FC = () => {
  // Navigation View State
  const [currentView, setCurrentView] = useState<'diary' | 'insights'>('diary');

  // Core Data State
  const [selectedMood, setSelectedMood] = useState<MoodLevel | null>(null);

  // New: Contextual Triggers
  const [triggers, setTriggers] = useState<string[]>([]);

  // New: Physiological Data
  const [sleepData, setSleepData] = useState<SleepData>({
    hours: 7.0,
    difficultyFallingAsleep: false,
    earlyWakeUp: false
  });
  const [menstrualDay, setMenstrualDay] = useState<number>(0);

  // New: Medication Data
  const [medication, setMedication] = useState<MedicationData>({
    taken: false,
    name: '',
    sideEffects: ''
  });

  // System State
  const [safetyOpen, setSafetyOpen] = useState(false);
  const [companionText, setCompanionText] = useState<string>("");
  const [loadingInsight, setLoadingInsight] = useState(false);

  // Safety trigger
  useEffect(() => {
    if (selectedMood === MoodLevel.ABYSS) {
      setSafetyOpen(true);
    }
  }, [selectedMood]);

  // Insight generator with enriched context
  useEffect(() => {
    let isMounted = true;
    if (selectedMood) {
      setLoadingInsight(true);

      const sleepIssues = [];
      if (sleepData.difficultyFallingAsleep) sleepIssues.push("Hard to sleep");
      if (sleepData.earlyWakeUp) sleepIssues.push("Early wake");

      getCompanionInsight(selectedMood, {
        triggers,
        sleepHours: sleepData.hours,
        medicationTaken: medication.taken,
        sleepIssues
      })
        .then(text => {
          if(isMounted) {
            setCompanionText(text);
            setLoadingInsight(false);
          }
        });
    }
    return () => { isMounted = false; };
  }, [selectedMood, triggers, sleepData.hours, medication.taken]);

  const toggleTrigger = (triggerId: string) => {
    if (triggers.includes(triggerId)) {
      setTriggers(triggers.filter(t => t !== triggerId));
    } else {
      setTriggers([...triggers, triggerId]);
    }
  };

  const handleMoodSelect = (mood: MoodLevel) => {
    setSelectedMood(mood);
  };

  return (
    <HashRouter>
      <div className="min-h-screen bg-stone-50 pb-24 max-w-lg mx-auto shadow-2xl overflow-hidden relative font-sans">

        {/* Header */}
        <header className="px-6 py-6 flex justify-between items-center bg-stone-50/80 backdrop-blur-sm sticky top-0 z-10">
          <div>
            <h1 className="text-2xl font-bold text-stone-800 tracking-tight">Fluctuations</h1>
            <p className="text-xs text-stone-400 mt-0.5">允许波动，精准记录</p>
          </div>
          <button className="text-stone-400 hover:text-stone-600 transition-colors bg-white p-2 rounded-full shadow-sm">
            <Settings size={20} />
          </button>
        </header>

        <main className="px-6 space-y-8 animate-slide-in">

          {currentView === 'diary' ? (
            <>
              {/* Section 1: Mood & Companion Insight */}
              <section className="space-y-3">
                 <div className="flex justify-between items-end">
                    <h2 className="text-sm font-bold text-stone-400 tracking-wide uppercase">当前状态</h2>
                    {selectedMood && (
                       <span className={`text-[10px] px-3 py-1.5 rounded-full bg-stone-200 text-stone-600 animate-fade-in max-w-[200px] truncate`}>
                          {loadingInsight ? "..." : companionText}
                       </span>
                    )}
                 </div>
                <MoodSelector 
                  selectedMood={selectedMood} 
                  onSelect={handleMoodSelect} 
                />
              </section>

              {/* Section 2: Contextual Triggers (New) */}
              <section>
                 <ContextualTriggers 
                    selectedTriggers={triggers}
                    onToggle={toggleTrigger}
                 />
              </section>

              {/* Section 3: Physiological (Sleep & Cycle Updated) */}
              <section>
                <PhysiologicalSection 
                  sleepData={sleepData}
                  onSleepChange={setSleepData}
                  menstrualDay={menstrualDay}
                  onMenstrualChange={setMenstrualDay}
                />
              </section>

              {/* Section 4: Medication (New Location & Logic) */}
              <section>
                <MedicationSection 
                  data={medication}
                  onChange={setMedication}
                />
              </section>
            </>
          ) : (
            /* INSIGHTS VIEW */
            <div className="space-y-6 animate-slide-in">
              <div className="bg-stone-900 text-stone-100 p-6 rounded-3xl shadow-lg">
                <h2 className="text-xl font-bold mb-2">多维模式洞察</h2>
                <p className="text-stone-400 text-sm leading-relaxed">
                  下图展示了情绪波动与生理节律（睡眠、经期）的潜在关联。
                </p>
              </div>
              <PatternChart />
            </div>
          )}

          <div className="h-4"></div>
        </main>

        {/* Floating Navigation */}
        <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-xl border-t border-stone-100 max-w-lg mx-auto z-40 pb-safe">
          <div className="flex justify-around py-4">
            <button 
              onClick={() => setCurrentView('diary')}
              className={`flex flex-col items-center gap-1 transition-colors ${currentView === 'diary' ? 'text-stone-800' : 'text-stone-400 hover:text-stone-600'}`}
            >
              <BookOpen size={22} className={currentView === 'diary' ? 'fill-stone-200' : ''} />
              <span className="text-[10px] font-bold">日记</span>
            </button>
            <button 
              onClick={() => setCurrentView('insights')}
              className={`flex flex-col items-center gap-1 transition-colors ${currentView === 'insights' ? 'text-stone-800' : 'text-stone-400 hover:text-stone-600'}`}
            >
              <BarChart2 size={22} className={currentView === 'insights' ? 'fill-stone-200' : ''} />
              <span className="text-[10px] font-bold">洞察</span>
            </button>
          </div>
        </nav>

        {/* Safety Modal */}
        <SafetyModal 
          isOpen={safetyOpen} 
          onClose={() => setSafetyOpen(false)} 
        />

      </div>
    </HashRouter>
  );
};

export default App;

import React from 'react';
