          else animationClass = 'animate-breathe-normal'; // Steady

          return (
            <button
              key={config.id}
              onClick={() => onSelect(config.id)}
              className={`
                group relative flex flex-col items-center justify-center p-2
                transition-all duration-500 ease-out
