import { GoogleGenAI } from "@google/genai";
import { MoodLevel } from "../types";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getCompanionInsight = async (
  mood: MoodLevel, 
  context: { 
    triggers: string[], 
    sleepHours: number, 
    medicationTaken: boolean,
    sleepIssues: string[]
  }
): Promise<string> => {
  try {
    if (!process.env.API_KEY) return "Gemini API Key missing.";

    const moodPrompts: Record<MoodLevel, string> = {
      [MoodLevel.ROCKET]: "State: Mania/Impulsive. Risk high.",
      [MoodLevel.FERRIS_WHEEL]: "State: Hypomania/Creative. Energy high.",
      [MoodLevel.STEADY]: "State: Baseline/Euthymia.",
      [MoodLevel.HOLDING_BREATH]: "State: Mild Depression/Masking.",
      [MoodLevel.DEEP_SEA]: "State: Moderate Depression/Slow.",
      [MoodLevel.ABYSS]: "State: Crisis/Darkness.",
    };

    const triggersText = context.triggers.length > 0 ? `Background factors: ${context.triggers.join(', ')}.` : "No specific triggers.";
    const sleepText = `Sleep: ${context.sleepHours}h (${context.sleepIssues.join(', ') || 'Normal'}).`;
    const medText = context.medicationTaken ? "Meds taken." : "Meds NOT taken.";

    const prompt = `
      You are a companion for someone with Bipolar Disorder.
      Current Status: ${moodPrompts[mood]}
      Context: ${triggersText} ${sleepText} ${medText}

      Task: Write a SINGLE sentence (max 25 words).
      Goal: Connect the context (sleep/triggers) to the mood if relevant. Be gentle.
      Tone: Non-judgmental, observant.
      Forbidden words: "hope", "cure", "happy", "should".
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text?.trim() || "Recorded.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Recorded.";
  }
};

export const generateClinicalReport = async (dataSummary: string): Promise<string> => {
    try {
        if (!process.env.API_KEY) return "API Key missing.";

        const prompt = `
            Act as a medical assistant. Based on the following patient data summary for the last 7 days:
            ${dataSummary}

            Generate a concise "Clinical Observation Brief" for a doctor's appointment.
            Structure:
            1. **Sleep Pattern**: Avg hours, anomalies.
            2. **Mood Stability**: Fluctuation range, dominant state.
            3. **Context**: Menstrual impact, triggers.
            4. **Medication Compliance**: Brief status.

            Keep it professional, objective, and bulleted. No fluff. Max 150 words.
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
        });

        return response.text?.trim() || "Report generation failed.";
    } catch (e) {
        console.error(e);
        return "Error generating report.";
    }
}

